import React, { useState } from "react";

function PDFAnalyzer() {
  const [selectedPDF, setSelectedPDF] = useState(null);
  const [chatContent, setChatContent] = useState("");

  const handlePDFSelect = (pdf) => {
    setSelectedPDF(pdf);
  };

  const handleChatSubmit = (e) => {
    e.preventDefault();
    // Add logic to handle chat submission
    setChatContent("");
  };

  return (
    <div className="container">
      <div className="left-panel">
        <div className="section">
          <h2>Select a PDF</h2>
          <select
            value={selectedPDF || ""}
            onChange={(e) => handlePDFSelect(e.target.value)}
          >
            <option value="">Choose a PDF</option>
            <option value="pdf1.pdf">PDF 1</option>
            <option value="pdf2.pdf">PDF 2</option>
            <option value="pdf3.pdf">PDF 3</option>
          </select>
        </div>

        <div className="section">
          <h2>Summary</h2>
          {/* Summary content goes here */}
        </div>

        <div className="section">
          <h2>Insights</h2>
          {/* Insights content goes here */}
        </div>

        <div className="section">
          <h2>Recommendations</h2>
          {/* Recommendations content goes here */}
        </div>

        <div className="section">
          <h2>Actions</h2>
          {/* Actions content goes here */}
        </div>

        <div className="section">
          <h2>Chat</h2>
          <div className="chat-container">
            <div className="chat-history">{/* Render chat history */}</div>
            <form onSubmit={handleChatSubmit} className="chat-input">
              <input
                type="text"
                value={chatContent}
                onChange={(e) => setChatContent(e.target.value)}
                placeholder="Ask about the document..."
              />
              <button type="submit">Send</button>
            </form>
          </div>
        </div>
      </div>

      <div className="right-panel">
        <h2>Select a PDF to view</h2>
        {/* PDF viewer goes here */}
      </div>
    </div>
  );
}

export default PDFAnalyzer;
